environment = "prod" # values can be prod, dev

if environment == "prod":
    storage_account = "cqlproddatahubdata"
else:
    storage_account = "cqldevdatahubdata"

full_paths = []
folders = mssparkutils.fs.ls(source_path)
for f in folders: 
    for z in mssparkutils.fs.ls(f"{f.path}"):
        full_paths.append(f"{f.path}/{z.name}")

lookup = {}
for f in full_paths:
    file_content = spark.read.text(f,wholetext=True).collect()[0].value
    try:
        contents = extract_content(file_content)
        file_name,creation_date = extract_creation_date(contents,f)
        lookup[file_name] = creation_date
    except Exception as e: continue

from pyspark.sql.functions import udf
from pyspark.sql.types import StringType

@udf(StringType())
def lookup_creation_date(val):
    return lookup.get(val,"None")

df_bronze_with_creationdate = df_bronze.withColumn("CreationDate", lookup_creation_date(df_bronze_filtered["FileName"]))

# Save dataframe 
if environment == "prod":
    path = "abfss://bronze@cqlproddatahubsynapse/AEMO/NEM12/nem12_bronze"
else:
    path = "abfss://bronze@cqldevdatahubsynapse/AEMO/NEM12/nem12_bronze"
df_bronze_with_creationdate.write.format("delta").mode("overwrite").option("overwriteSchema","true").option("path",path).saveAsTable(f"aemo_bronze.nem12_bronze")
